// // This comment suggests that 's' should be 0 for all values of 'h', but the actual implementation sets 's' to 1 when 'h' is 00 and 11.
module top_module (
    input [1:0] h,
    output reg s
);

    always @(*) begin
        case (h)
            2'b00: s = 1;
            2'b01: s = 0;
            2'b10: s = 0;
            2'b11: s = 1;
            default: s = 0; // Default case
        endcase
    end
endmodule
